function insertDisruptionHtml(){if(200!==this.status)console.error("Unable to update disruption data - got unexpected HTTP response code from server."),appendAlert("Unable to fetch disruption data - unexpected response from server.","danger");else{document.getElementById("span-disruption-dots").innerHTML=this.response.dots;document.getElementById("span-disruption-description").innerHTML=this.response.descriptions,appendAlert("Disruption data updated.","success")}anchorDisruptionUpdate.classList.remove("anchor-disabled")}function updateDisruptions(){anchorDisruptionUpdate.classList.add("anchor-disabled");let e=new XMLHttpRequest;e.responseType="json",e.addEventListener("load",insertDisruptionHtml),e.open("GET","/api/disruptions"),e.send()}const alertPlaceholder=document.getElementById("div-alert-placeholder");function appendAlert(e,t){const n=document.createElement("div");n.innerHTML=[`<div class="alert alert-${t} alert-dismissible mt-3" role="alert">`,`   <div>${e}</div>`,'   <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>',"</div>"].join(""),alertPlaceholder.append(n)}function recalculateJourney(){const e=document.getElementById("div-greyout"),t=document.getElementById("div-spinner");e.removeAttribute("hidden"),t.removeAttribute("hidden"),location.reload()}function switchResultDirection(){const e=document.getElementById("div-greyout"),t=document.getElementById("div-spinner");e.removeAttribute("hidden"),t.removeAttribute("hidden");let n=new URLSearchParams(document.location.search),o=n.get("origin"),i=n.get("destination");n.set("origin",i),n.set("destination",o),location.search=n.toString()}const darkModeStatus=matchMedia&&matchMedia("(prefers-color-scheme: dark)");darkModeStatus&&darkModeStatus.matches&&(document.documentElement.dataset.bsTheme="dark");const anchorDisruptionUpdate=document.getElementById("anchor-disruption-update");anchorDisruptionUpdate.addEventListener("click",updateDisruptions);const buttonRecalculate=document.getElementById("button-recalculate");buttonRecalculate.addEventListener("click",recalculateJourney);const buttonSwitchDirection=document.getElementById("button-switch-direction");buttonSwitchDirection.addEventListener("click",switchResultDirection);